snippets.C0679:
-- C0679 · Deadlock/locking demo (2 sesiones) (Avanzado, Base de datos)
-- Ejecutar en 2 sesiones.
-- Pre:
-- IF OBJECT_ID('dbo.demo_lock','U') IS NULL
--   CREATE TABLE dbo.demo_lock(id int primary key, val int);
-- IF NOT EXISTS (SELECT 1 FROM dbo.demo_lock WHERE id=1)
--   INSERT INTO dbo.demo_lock(id,val) VALUES (1,10),(2,20);

-- SESIÓN A
BEGIN TRAN;
  UPDATE dbo.demo_lock SET val = val + 1 WHERE id = 1;
  WAITFOR DELAY '00:00:03';
  UPDATE dbo.demo_lock SET val = val + 1 WHERE id = 2;
COMMIT;

-- SESIÓN B
BEGIN TRAN;
  UPDATE dbo.demo_lock SET val = val + 1 WHERE id = 2;
  WAITFOR DELAY '00:00:03';
  UPDATE dbo.demo_lock SET val = val + 1 WHERE id = 1;
COMMIT;

-- Mitigación: mismo orden de locks (id asc), transacciones cortas, índices correctos,
-- y en algunos casos snapshot isolation.
